"""Auto-generated training script for wifi_csi_har (UT-HAR).
Task: WiFi CSI人体行为识别，坐站走摔倒挥手，CPU，准确率85%，UT-HAR数据集
Target accuracy: 85%
Device: cpu
Generated by SurveyMind csi_har_scaffold.py
"""
from __future__ import annotations
import json
