import numpy as np
import torch
import torch.nn as nn
import torch.nn.functional as F
from torch.utils.data import Dataset, DataLoader

# ---------------------------------------------------------------------------
# Model definitions
# ---------------------------------------------------------------------------

class _ResBlock1D(nn.Module):
    def __init__(self, channels: int, kernel_size: int = 3):
        super().__init__()
        pad = kernel_size // 2
        self.conv1 = nn.Conv1d(channels, channels, kernel_size, padding=pad)
        self.bn1 = nn.BatchNorm1d(channels)
        self.conv2 = nn.Conv1d(channels, channels, kernel_size, padding=pad)
        self.bn2 = nn.BatchNorm1d(channels)

    def forward(self, x):
        residual = x
        x = F.relu(self.bn1(self.conv1(x)))
        x = self.bn2(self.conv2(x))
        return F.relu(x + residual)


class CSIResNet1D(nn.Module):
    """1D ResNet for CSI time-series classification."""

    def __init__(self, in_channels: int, num_classes: int, base_channels: int = 64):
        super().__init__()
        self.stem = nn.Sequential(
            nn.Conv1d(in_channels, base_channels, kernel_size=7, padding=3),
            nn.BatchNorm1d(base_channels),
            nn.ReLU(),
        )
        self.blocks = nn.Sequential(
            _ResBlock1D(base_channels),
            _ResBlock1D(base_channels),
            nn.Conv1d(base_channels, base_channels * 2, kernel_size=3, stride=2, padding=1),
            nn.BatchNorm1d(base_channels * 2),
            nn.ReLU(),
            _ResBlock1D(base_channels * 2),
            _ResBlock1D(base_channels * 2),
        )
        self.pool = nn.AdaptiveAvgPool1d(1)
        self.fc = nn.Linear(base_channels * 2, num_classes)

    def forward(self, x):
        # x: [B, C, T]
        x = self.stem(x)
        x = self.blocks(x)
        x = self.pool(x).squeeze(-1)
        return self.fc(x)


# ---------------------------------------------------------------------------
# Dataset loader
# ---------------------------------------------------------------------------

TARGET_ACTIONS = ["sit", "stand", "walk", "fall", "wave"]
UT_HAR_LABEL_MAP = {"lie": 0, "fall": 1, "walk": 2, "pickup": 3, "run": 4, "sit": 5, "stand": 6}


def _subset_labels(y_full, target_actions):
    """Map UT-HAR native labels (0-6) to our 5-class subset.
    wave is not in standard UT-HAR; we map it from gestures or treat as unseen.
    For now, we use the available 4 classes + relabel pickup→wave as placeholder.
    """
    ut_to_target = {}
    for name, ut_id in UT_HAR_LABEL_MAP.items():
        if name in target_actions:
            ut_to_target[ut_id] = target_actions.index(name)
    # If 'wave' is not in UT-HAR, map 'pickup' → 'wave' as closest gesture class
    if "wave" in target_actions and "wave" not in UT_HAR_LABEL_MAP:
        ut_to_target[UT_HAR_LABEL_MAP["pickup"]] = target_actions.index("wave")
    mask = np.isin(y_full, list(ut_to_target.keys()))
    y_subset = np.array([ut_to_target[yi] for yi in y_full[mask]], dtype=np.int64)
    return mask, y_subset


class UTHARDataset(Dataset):
    """UT-HAR WiFi Activity Recognition Dataset – 5-class subset.
    Source: https://github.com/ermongroup/Wifi_Activity_Recognition
    Native classes: lie, fall, walk, pickup, run, sit, stand → mapped to target actions.
    """

    def __init__(self, data_dir: str, split: str = "train", preprocess: bool = True):
        self.data_dir = Path(data_dir)
        self.preprocess = preprocess
        self.samples, self.labels = self._load(split)

    def _load(self, split: str):
        x_path = self.data_dir / "data_x.npy"
        y_path = self.data_dir / "data_y.npy"
        if not x_path.exists():
            raise FileNotFoundError(
                f"UT-HAR data not found at {self.data_dir}. "
                f"Run: git clone https://github.com/ermongroup/Wifi_Activity_Recognition {self.data_dir}"
            )
        X = np.load(str(x_path)).astype(np.float32)
        y = np.load(str(y_path)).astype(np.int64)
        mask, y_sub = _subset_labels(y, TARGET_ACTIONS)
        X = X[mask]
        return self._split(X, y_sub, split)

    @staticmethod
    def _split(X, y, split: str):
        n = len(y)
        rng = np.random.RandomState(42)
        idx = rng.permutation(n)
        t = int(0.6 * n)
        v = int(0.8 * n)
        splits = {"train": idx[:t], "val": idx[t:v], "test": idx[v:]}
        sel = splits[split]
        return X[sel], y[sel]

    def __len__(self):
        return len(self.labels)

    def __getitem__(self, idx):
        x = torch.tensor(self.samples[idx], dtype=torch.float32).T  # [C, T]
        y = torch.tensor(self.labels[idx], dtype=torch.long)
        if self.preprocess:
            x = _preprocess_csi(x)
        return x, y


def _preprocess_csi(x: torch.Tensor) -> torch.Tensor:
    """amplitude_only: hampel → bandpass (placeholder) → per-channel z-score."""
    # Hampel outlier removal (low-pass median for stability)
    for ch in range(x.shape[0]):
        x[ch] = hampel_filter_1d(x[ch], k=5, threshold=3.0)
    # Per-channel z-score normalization
    mu = x.mean(dim=-1, keepdim=True)
    sigma = x.std(dim=-1, keepdim=True) + 1e-8
    return (x - mu) / sigma


# ---------------------------------------------------------------------------
# Preprocessing transforms
# ---------------------------------------------------------------------------

def hampel_filter_1d(x: torch.Tensor, k: int = 5, threshold: float = 3.0) -> torch.Tensor:
    """Hampel filter for outlier removal on 1D signal."""
    T = x.shape[-1]
    out = x.clone()
    for i in range(k, T - k):
        window = x[..., i - k : i + k + 1]
        med = window.median(dim=-1).values
        mad = (window - med.unsqueeze(-1)).abs().median(dim=-1).values
        dev = (x[..., i] - med).abs()
        mask = dev > threshold * 1.4826 * mad
        out[..., i] = torch.where(mask, med, x[..., i])
    return out


# ---------------------------------------------------------------------------
# Metrics logging
# ---------------------------------------------------------------------------

LOG_DIR = Path("experiments/20260623_143446")

def log_metrics(epoch: int, metrics: dict, log_path: Path | None = None) -> None:
    if log_path is None:
        log_path = LOG_DIR / "train_log.jsonl"
    log_path.parent.mkdir(parents=True, exist_ok=True)
    with open(log_path, "a") as f:
        f.write(json.dumps({"epoch": epoch, "ts": time.time(), **metrics}) + "\n")


# ---------------------------------------------------------------------------
# Training loop
# ---------------------------------------------------------------------------

def train_epoch(model, loader, optimizer, criterion, device):
    model.train()
    total_loss, correct, n = 0.0, 0, 0
    for x, y in loader:
        x, y = x.to(device), y.to(device)
        optimizer.zero_grad()
        logits = model(x)
        loss = criterion(logits, y)
        loss.backward()
        torch.nn.utils.clip_grad_norm_(model.parameters(), 1.0)
        optimizer.step()
        total_loss += loss.item() * len(y)
        correct += (logits.argmax(1) == y).sum().item()
        n += len(y)
    return total_loss / n, correct / n


def eval_epoch(model, loader, criterion, device):
    model.eval()
    total_loss, correct, n = 0.0, 0, 0
    with torch.no_grad():
        for x, y in loader:
            x, y = x.to(device), y.to(device)
            logits = model(x)
            loss = criterion(logits, y)
            total_loss += loss.item() * len(y)
            correct += (logits.argmax(1) == y).sum().item()
            n += len(y)
    return total_loss / n, correct / n


def train(
    data_dir: str = "data/UT-HAR",
    checkpoint_dir: str = str(LOG_DIR),
    epochs: int = 50,
    batch_size: int = 32,
    lr: float = 1e-3,
    device_str: str = "cpu",
    seed: int = 42,
) -> dict:
    torch.manual_seed(seed)
    np.random.seed(seed)
    device = torch.device(device_str)

    # Datasets
    train_ds = UTHARDataset(data_dir, split="train")
    val_ds   = UTHARDataset(data_dir, split="val")
    test_ds  = UTHARDataset(data_dir, split="test")

    train_loader = DataLoader(train_ds, batch_size=batch_size, shuffle=True,  num_workers=0)
    val_loader   = DataLoader(val_ds,   batch_size=batch_size, shuffle=False, num_workers=0)
    test_loader  = DataLoader(test_ds,  batch_size=batch_size, shuffle=False, num_workers=0)

    # Sample shape
    sample_x, _ = train_ds[0]
    in_channels = sample_x.shape[0]

    # Model
    model = CSIResNet1D(in_channels=in_channels, num_classes=5).to(device)

    n_params = sum(p.numel() for p in model.parameters()) / 1e6
    print(f"Model: CSIResNet1D, params: {n_params:.3f}M, device: {device}")

    criterion = nn.CrossEntropyLoss()
    optimizer = torch.optim.Adam(model.parameters(), lr=lr, weight_decay=1e-4)
    scheduler = torch.optim.lr_scheduler.ReduceLROnPlateau(optimizer, patience=5, factor=0.5)

    out_dir = Path(checkpoint_dir)
    out_dir.mkdir(parents=True, exist_ok=True)
    log_path = out_dir / "train_log.jsonl"

    best_val_acc, patience_cnt, best_epoch = 0.0, 0, 0
    early_stop_patience = 10

    for epoch in range(1, epochs + 1):
        t0 = time.time()
        tr_loss, tr_acc = train_epoch(model, train_loader, optimizer, criterion, device)
        va_loss, va_acc = eval_epoch(model, val_loader, criterion, device)
        scheduler.step(va_loss)
        elapsed = time.time() - t0

        metrics = dict(
            train_loss=round(tr_loss, 4), train_acc=round(tr_acc, 4),
            val_loss=round(va_loss, 4), val_acc=round(va_acc, 4),
            lr=round(optimizer.param_groups[0]["lr"], 6), epoch_s=round(elapsed, 2),
        )
        log_metrics(epoch, metrics, log_path)

        if va_acc > best_val_acc:
            best_val_acc = va_acc
            best_epoch = epoch
            patience_cnt = 0
            ckpt_path = out_dir / "best_model.pt"
            torch.save({"model_state_dict": model.state_dict(),
                         "epoch": epoch, "val_acc": va_acc,
                         "arch": "csi_resnet1d", "num_classes": 5,
                         "in_channels": in_channels}, ckpt_path)
        else:
            patience_cnt += 1

        print(f"Epoch {epoch:3d}/{epochs} | "
              f"train_loss={tr_loss:.4f} acc={tr_acc:.3f} | "
              f"val_loss={va_loss:.4f} acc={va_acc:.3f} | "
              f"best={best_val_acc:.3f}@{best_epoch} | {elapsed:.1f}s")

        if patience_cnt >= early_stop_patience:
            print(f"Early stopping at epoch {epoch}")
            break

    # Test evaluation
    model.load_state_dict(torch.load(out_dir / "best_model.pt",
                                     map_location=device)["model_state_dict"])
    _, test_acc = eval_epoch(model, test_loader, criterion, device)
    print(f"\nTest accuracy: {test_acc:.4f} (target: 0.85)")

    result = dict(
        best_val_acc=best_val_acc, test_acc=test_acc,
        best_epoch=best_epoch, total_epochs=epoch,
        target_met=test_acc >= 0.85,
        checkpoint=str(out_dir / "best_model.pt"),
        arch="csi_resnet1d", num_classes=5, in_channels=in_channels,
    )
    (out_dir / "result.json").write_text(json.dumps(result, indent=2))
    return result


if __name__ == "__main__":
    import argparse
    ap = argparse.ArgumentParser()
    ap.add_argument("--data-dir", default="data/UT-HAR")
    ap.add_argument("--checkpoint-dir", default=str(LOG_DIR))
    ap.add_argument("--epochs", type=int, default=50)
    ap.add_argument("--batch-size", type=int, default=32)
    ap.add_argument("--lr", type=float, default=1e-3)
    ap.add_argument("--device", default="cpu")
    ap.add_argument("--seed", type=int, default=42)
    args = ap.parse_args()
    result = train(
        data_dir=args.data_dir,
        checkpoint_dir=args.checkpoint_dir,
        epochs=args.epochs,
        batch_size=args.batch_size,
        lr=args.lr,
        device_str=args.device,
        seed=args.seed,
    )
    print("\nFinal result:")
    print(json.dumps(result, indent=2))
